+)
+
+func TestBackoffGrows(t *testing.T) {
+	p := &RetryPolicy{baseDelay: 10 * time.Millisecond}
+	if p.Backoff(0) >= p.Backoff(3) {
+		t.Fatal("expected backoff to grow with attempts")
+	}
